            sample_c1 = signed_to_sample(signed_c1)
            sample_c2 = signed_to_sample(signed_c2)
    else:
        sample_c0 = signed_to_sample(signed_c0)
        sample_c1 = signed_to_sample(signed_c1)
        sample_c2 = signed_to_sample(signed_c2)
    raw = recombine_rggb(sample_c0, sample_c1, sample_c2)
    return raw.astype("<u2", copy=False).tobytes()
